@st.cache_data
def load_csv(file):
 return pd.read_csv(file)

uploaded_file = st.file_uploader("Upload CSV", type="csv")

if uploaded_file:
 st.dataframe(load_csv(uploaded_file))

import streamlit as st

@st.cache_data
def square(x):
 return x ** 2

num = st.number_input("Number")
st.write(square(num))

import streamlit as st
import requests

@st.cache_data
def fetch_data():
 response = requests.get("https://httpbin.org/get")
 return response.json()

st.write(fetch_data())

