import streamlit as st
import pandas as pd

@st.cache_data
def load_sales():
 return pd.DataFrame({"Product":["A","B","C"],"Sales":[100,150,120]})

df = load_sales()

st.dataframe(df)
st.bar_chart(df.set_index("Product"))

import streamlit as st

if st.button("Save"):
 st.toast("Data Saved Successfully!")

import streamlit as st

weight = st.number_input("Weight (kg)", min_value=1.0)
height = st.number_input("Height (m)", min_value=0.1)

if st.button("Calculate BMI"):
 bmi = weight / (height ** 2)
 st.metric("BMI", round(bmi,2))

 if bmi < 18.5:
 st.info("Underweight")
 elif bmi < 25:
 st.success("Normal")
 elif bmi < 30:
 st.warning("Overweight")
 else:
 st.error("Obese")

import streamlit as st

conversion = st.selectbox("Conversion", ["Celsius to Fahrenheit","Fahrenheit to Celsius"])
temp = st.number_input("Temperature")

if st.button("Convert"):
 if conversion == "Celsius to Fahrenheit":
 st.write(temp * 9 / 5 + 32)
 else:
 st.write((temp - 32) * 5 / 9)
